-- BLOCO 1 (parte 6/6) — Revisão linguística pílulas PVI (4 variants pt-BR)

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Construindo algo que importa. A inquietude faz parte do trabalho.", "tension_label": "Movimento ↔ Pausa"}, "m2": {"scene": "Rodrigo, 36, abriu a empresa de consultoria há oito meses. Está funcionando — funcionando de verdade. Tem clientes e dinheiro. Mas há uma inquietude que ele não esperava. Em alguns dias acorda sabendo que isso vai falhar. Em outros, vai escalar. As duas coisas parecem igualmente plausíveis. Está trabalhando dez horas por dia porque parar parece perigoso — pausar parece reverter o ritmo. A esposa deixa recados gentis: 'Vem jantar?' O corpo dele roda em adrenalina e café. Sabe que isso não é sustentável. Também sabe que se desacelerar, algo pode desmoronar. É quarta à tarde. Uma oportunidade de cliente acabou de chegar, dobraria capacidade e horas. Está prestes a aceitar.", "question": "O que Rodrigo está construindo, e o que está arriscando ao construir desse jeito?"}, "m4": {"question": "Agora — essa inquietude parece sinal de que você está fazendo algo certo, ou de que algo precisa mudar? O que te fez responder assim?", "instruction": "Uma frase só. E logo abaixo, o que te fez responder assim."}, "m3_1": {"context": "", "question": "Quando o ritmo aperta, você tende a manter o passo (acreditando que é o que precisa) ou a parar pra respirar?", "pole_left": "Acelerar", "pole_right": "Pausar"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Pauso pra entender o que está sendo tirado — não pra parar de construir, mas pra saber qual é o custo.", "followup": "O que clareza sobre o custo mudaria?", "followup_type": "question"}, {"key": "B", "text": "Diminuo o ritmo — mesmo que doa.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "C", "text": "Termino esta fase, depois reavalio.", "followup": "O que você espera que esteja diferente quando essa fase acabar?", "followup_type": "question"}, {"key": "D", "text": "Empurro — o custo faz parte do trabalho.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}], "scenario": "Você está construindo algo há meses. Está funcionando — mas o ritmo está tirando algo de você. Você ainda não consegue dizer se é problema ou só o custo. Está num ponto de decisão."}, "m3_3": {"q1": "Lembre de uma vez em que estava construindo algo que importava e a inquietude estava presente. O que estava construindo, e como ela aparecia em você?", "q2": "Como você se manteve em pé — continuar construindo enquanto o chão tremia? O que te sustentou?", "scoring_note": "", "q_transversal": "No meio dessa correria — o que você fez ficou bom, ou o ritmo cobrou o preço?"}}$rdwth_final$::jsonb
WHERE id = '0fc0b2d5-1eca-4158-9dad-29ac3ed84fd2';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Estou construindo algo real. E aprendendo a construir dentro da instabilidade.", "tension_label": "Movimento ↔ Pausa"}, "m2": {"scene": "Larissa, 32, está há quatro anos criando dois filhos e construindo carreira em tech. A carreira é ritmo — promoções, visibilidade, projetos com os quais ela se importa. Os filhos são crescimento — virando pessoas, precisando da presença dela. Os dois acelerando. Está se virando movendo mais rápido e dormindo menos. A paciência ficou mais fina. A alegria ainda está, mas por baixo corre: não sei por quanto tempo consigo sustentar isso. Ainda não está em burnout. Está na estação que vem antes disso. Uma oportunidade acabou de surgir: um cargo de liderança que ia moldar a trajetória dela. Exige presença e ritmo. Ela tem um filho de sete anos com ansiedade de separação e uma de três que acabou de começar a pré-escola. Tudo de uma vez.", "question": "Qual é a decisão real de Larissa, e o que acontece se ela pausar pra avaliar?"}, "m4": {"question": "Respondendo isso, você estava mais ligado no que está construindo ou no que isso está custando? Qual estava mais presente?", "instruction": "Uma frase basta. Nomeie pra onde sua atenção foi — não pra onde queria que tivesse ido."}, "m3_1": {"context": "", "question": "Quando algo te tira o chão enquanto você constrói, você lê como sinal de que algo está errado, ou de que está crescendo?", "pole_left": "Sinal de parar", "pole_right": "Sinal de continuar"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Aceito — o crescimento vale o custo.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "B", "text": "Examino como seria consolidar — do que essa construção precisa de mim antes de eu adicionar mais?", "followup": "Como seria dizer não em nome do que já está aqui?", "followup_type": "question"}, {"key": "C", "text": "Aceito mas renegocio o cronograma — começo mais devagar, em fases.", "followup": "O que precisaria pra você ir em velocidade total?", "followup_type": "question"}, {"key": "D", "text": "Aceito mas digo às pessoas que estou no limite — torno os limites públicos enquanto sigo.", "followup": "O que muda quando os outros sabem das suas bordas?", "followup_type": "question"}], "scenario": "Você está no meio de construir. A inquietude é real — você sente. E tem uma oportunidade real na sua frente: algo que amplificaria o que está construindo, mas aumentaria o ritmo e a pressão agora. Tem que escolher: aceita ou protege o que já está gerenciando?"}, "m3_3": {"q1": "Lembre de um momento em que teve que escolher entre manter ritmo e criar pausa enquanto construía algo real. O que escolheu, e o que estava em jogo?", "q2": "O que tornou possível fazer essa escolha? Tinha apoio, clareza, confiança em algo, ou só teve que agir sem isso?", "scoring_note": "", "q_transversal": "Quando você escolheu manter o ritmo ou pausar — a escolha foi boa, ou você só agiu no automático?"}}$rdwth_final$::jsonb
WHERE id = '018bd64a-6fa9-41eb-8461-881e83b21786';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "Algo está crescendo. O crescimento vem com inquietude. As duas coisas acontecem juntas.", "tension_label": "Movimento ↔ Pausa"}, "m2": {"scene": "Marcelo, 48, passou quinze anos construindo reputação na área dele. Agora está construindo algo novo — um tipo diferente de trabalho, mais alinhado, com mais em jogo porque é mais verdadeiro. O novo está ganhando tração. O antigo ainda chama. Está construindo o novo mantendo parte do antigo, o que significa que nunca está plenamente dentro de nenhum dos dois. Move-se entre eles, e o movimento em si virou a velocidade padrão dele. A filha adulta perguntou mês passado: 'Pai, você nunca para?' Ele riu, mas a pergunta ficou. Está construindo algo que importa pra ele. O ritmo da construção está custando algo que ele só agora está começando a nomear. Um nome forte da área dele acabou de pedir colaboração num projeto visível — essa é a validação que ele queria há dois anos. O timing é quando ele já está no limite.", "question": "Do que Marcelo tem medo se desacelerar, e do que tem medo se não desacelerar?"}, "m4": {"question": "Se você tivesse que escolher uma palavra pro que está carregando agora — o peso de construir — qual seria? E essa palavra é uma queixa ou uma descrição?", "instruction": "A palavra, e depois uma frase: é queixa ou descrição? A distinção importa."}, "m3_1": {"context": "", "question": "Quando você constrói algo importante, prefere proteger o ritmo (acelerar, fazer mais) ou proteger sua presença (desacelerar, com cuidado)?", "pole_left": "Proteger ritmo", "pole_right": "Proteger presença"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Continuo como está — a resposta é em direção a algo, confio nisso.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "B", "text": "Examino o custo honestamente — não pra parar, mas pra saber o que estou de fato escolhendo.", "followup": "Do que precisaria pra ficar nesse ritmo de olhos abertos?", "followup_type": "question"}, {"key": "C", "text": "Mudo algo estrutural — acho um jeito de desacelerar o ritmo mantendo o movimento pra frente.", "followup": "O que precisaria estar diferente em como você trabalha pra fazer isso?", "followup_type": "question"}, {"key": "D", "text": "Trago pra fora — conto pras pessoas afetadas pelo seu ritmo que você está questionando.", "followup": "O que elas te diriam se você perguntasse?", "followup_type": "question"}], "scenario": "Você está construindo algo real. E está se movendo mais rápido do que pensava. O ritmo é genuíno — não é forçado. Mas o custo também é: menos sono, menos espaço, menos conexão com pessoas que importam. Ainda não está em burnout, mas vê a direção. E hoje, algo dentro está perguntando: você está correndo em direção a algo ou fugindo de algo?"}, "m3_3": {"q1": "Lembre de uma vez específica em que estava construindo algo significativo e percebeu que estava num ritmo que estava te custando. O que estava construindo, e qual era o custo?", "q2": "O que te deixou consciente do custo? Sinal físico, feedback de alguém, sua própria reflexão? O que precisaria acontecer pra você agir em cima disso?", "scoring_note": "", "q_transversal": "No ritmo em que estava — o que você fez atendia seu próprio padrão, ou você estava cortando atalhos que não queria?"}}$rdwth_final$::jsonb
WHERE id = 'dc481158-0771-4dfe-ae93-89e6bf030eff';

UPDATE pill_content_variations
SET content = $rdwth_final${"m1": {"phrase": "O movimento em si é o ponto. O chão sob ele também. Estou descobrindo como ficar de pé enquanto construo.", "tension_label": "Movimento ↔ Pausa"}, "m2": {"scene": "Patrícia, 41, saiu do corporativo há dois anos para construir algo seu. Está funcionando — não famosa, não rica, mas viva e relevante. O ritmo exigido está lhe ensinando coisas que ela nunca soube. Está descobrindo que consegue segurar complexidade, lidar com incerteza, manter a calma na inquietude. Também está esquecendo o que é tédio, o que é uma manhã sem propósito. Está construindo um ritmo que parece essencial. Mas por baixo há uma pergunta que ela não fez: o que estou evitando ao continuar em movimento? Tem um fundo de sabático intocado. Um mentor se ofereceu para ajudá-la a pensar em sistemas sustentáveis. Ela continua dizendo sim ao ritmo e não ao descanso, sem entender por quê.", "question": "O que Patrícia está construindo, e o que essa inquietude está escondendo dela?"}, "m4": {"question": "Algo em você quer continuar. Outra coisa em você quer parar e olhar em volta. Agora, qual voz está mais alta — e em qual delas você confia mais?", "instruction": "Nomeie as duas vozes e diga em qual você confia mais."}, "m3_1": {"context": "", "question": "Quando algo seu está dando certo mas o custo aparece, você prefere crescer mais rápido, ou cuidar do que já tem?", "pole_left": "Crescer mais", "pole_right": "Cuidar do que tem"}, "m3_2": {"framing": "O que você abre mão — e quem mais é afetado?", "options": [{"key": "A", "text": "Demoro na percepção — entendo o que a pressão está realmente pedindo de mim antes de responder.", "followup": "O que mudaria se você respondesse à pressão em vez de alimentá-la?", "followup_type": "question"}, {"key": "B", "text": "Pauso de propósito — tiro tempo real pra ver o que está por baixo da corrida.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}, {"key": "C", "text": "Acelero ainda mais — dobro a aposta no que está funcionando antes que algo mude.", "followup": "Do que você tem medo que aconteça se não fizer isso?", "followup_type": "question"}, {"key": "D", "text": "Continuo me movendo — o ritmo é o que mantém isso vivo.", "followup": "O que você abre mão — e quem mais é afetado?", "followup_type": "cost"}], "scenario": "Você está construindo isso há um tempo. Está vivo. Importa. E há um tipo específico de pressão por baixo que você está começando a notar — não vinda de obstáculos, mas do ritmo. Da escolha. Do fato de que você poderia desacelerar mas não desacelerou. Do fato de que pausar parece perigoso. Você está no momento de notar isso."}, "m3_3": {"q1": "Lembre de uma vez em que você construiu algo enquanto mantinha estabilidade ou presença suficiente no resto da sua vida. O que estava construindo, e o que te impediu de cair em puro ritmo?", "q2": "O que te protegeu — um limite, uma relação, um ritmo, uma crença? O que aconteceria se essa proteção não estivesse lá?", "scoring_note": "", "q_transversal": "O que protegeu o que você fez do ritmo acelerado?"}}$rdwth_final$::jsonb
WHERE id = '6b7bbe07-3537-418a-97e5-924cd7ae92b2';